import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Button from './ui/Button';
import { Input } from 'postcss';

const BookUpdate = () => {
  const {id} = useParams();
  const [bookId,setBookId] = useState("");
  const [bookTitle, setBookTitle] = useState("");
  const [bookDescription, setBookDescription] = useState("");
  const [bookPage, setBookPage] = useState("");
  const navigate = useNavigate()

  const bookToUpdate = {
    _id:parseInt(bookId),
    title:bookTitle,
    description:bookDescription,
    page:parseInt(bookPage)
}


  useEffect(()=>{
    fetch(`http://localhost:3000/api/book/${id}`, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(bookToUpdate),
    })
      .then((response) => {
        if (response.ok) {
          console.log("Livre ajouté avec succès !");
          // Réinitialiser les champs du formulaire
          setBookId("");
          setBookTitle("");
          setBookDescription("");
          setBookPage("");
          navigate("/BookList");
        } else {
          throw new Error("Erreur lors de l'envoi des données.");
        }
      })
      .catch((error) => console.error("Erreur :", error));

  },[id]);


  return (
    <div>
      <div className="w-[50vh] h-auto">
            <h1 className="text-center text-2xl font-bold mb-4">Ajouter un Livre</h1>
      
            {/* Champ ID */}
            <div className="mb-4">
              <Input
                placeholder="Entrez l'ID du livre"
                value={bookId}
                onChange={(e) => setBookId(e.target.value)}
              />
            </div>
      
            {/* Champ Titre */}
            <div className="mb-4">
              <Input
                placeholder="Entrez le titre du livre"
                value={bookTitle}
                onChange={(e) => setBookTitle(e.target.value)}
              />
            </div>
      
            {/* Champ Description */}
            <div className="mb-4">
              <Input
                placeholder="Entrez la description du livre"
                value={bookDescription}
                onChange={(e) => setBookDescription(e.target.value)}
              />
            </div>
      
            {/* Champ Nombre de Pages */}
            <div className="mb-4">
              <Input
                placeholder="Entrez le nombre de pages"
                type="number"
                value={bookPage}
                onChange={(e) => setBookPage(e.target.value)}
              />
            </div>
      
            {/* Bouton Submit */}
            <Button>Submit</Button>
          </div>
    </div>
  );
};

export default BookUpdate;
